import javax.swing.*;
public class ThreadBug {
    static int count = 0;
    static JLabel label = new JLabel("0");
    public static void main(String[] args) {
        JFrame f = new JFrame();
        JButton btn = new JButton("Click");
        btn.addActionListener(e -> {
            count++;
            label.setText(String.valueOf(count));  // correct: on EDT
        });
        // Bug: updating UI from non-EDT thread:
        new Thread(() -> label.setText("background")).start();  // unsafe
        f.add(btn); f.add(label);
    }
}
